// Quick test: sign up a creator, then use the returned JWT to query PostgREST directly.
// If PGRST301 appears, the JWT drift blocker for US-036 is still live.

const supabaseUrl = process.env.SUPABASE_URL;
const anonKey = process.env.SUPABASE_ANON_KEY;
if (!supabaseUrl || !anonKey) {
  console.error("SUPABASE_URL + SUPABASE_ANON_KEY required");
  process.exit(1);
}

const unique = Date.now();
const signupRes = await fetch(`${supabaseUrl}/functions/v1/auth-signup-creator`, {
  method: "POST",
  headers: {
    "Content-Type": "application/json",
    Authorization: `Bearer ${anonKey}`,
    apikey: anonKey,
  },
  body: JSON.stringify({
    username: `jwt_drift_${unique}`,
    tiktok_handle: `jwt_drift_tt_${unique}`,
  }),
});
const signupBody = await signupRes.json();
console.log("signup:", signupRes.status, JSON.stringify(signupBody).slice(0, 200));

if (signupRes.status !== 200) process.exit(1);

const token = signupBody.token;
const userId = signupBody.user_id;

// Now use that token against PostgREST directly — this is the exact path the profile screen uses.
const postgrestRes = await fetch(
  `${supabaseUrl}/rest/v1/creator_profiles?select=user_id&user_id=eq.${userId}`,
  {
    headers: {
      apikey: anonKey,
      Authorization: `Bearer ${token}`,
    },
  },
);
const postgrestBody = await postgrestRes.text();
console.log("postgrest:", postgrestRes.status, postgrestBody);

if (postgrestRes.status === 200) {
  console.log("JWT DRIFT RESOLVED — PostgREST accepts Marketify JWT");
  // Clean up via service role if available
  const srv = process.env.SUPABASE_SERVICE_ROLE_KEY;
  if (srv) {
    await fetch(`${supabaseUrl}/rest/v1/users?id=eq.${userId}`, {
      method: "DELETE",
      headers: { apikey: srv, Authorization: `Bearer ${srv}` },
    });
  }
  process.exit(0);
} else {
  console.log("JWT DRIFT STILL LIVE — PostgREST rejected Marketify JWT");
  process.exit(2);
}
EOF
