33	
34	// US-035 — creator profile. Shows TikTok + Instagram handles with their
35	// denormalized follower counts / avg views, a "Stale" chip when the latest
36	// metric_snapshot was flipped to status='stale' by the hourly cron, and an
37	// Add / Unlink flow wired to the manage-social-link edge function.
38	//
39	// Spec gap: the story AC says "Stale chip appears when metrics_stale_at is
40	// non-null", but there is no metrics_stale_at column on creator_profiles
41	// (see us_004 + the us_011 cron which flips metric_snapshots.status='stale'
42	// instead). The chip is therefore derived from
43	// metric_snapshots WHERE is_latest = true AND status = 'stale', which is
44	// the signal the cron actually produces per docs/tech-architecture.md §16.
45	//
46	// US-036 extends this screen with per-platform pull-to-refresh that calls
47	// the metrics-refresh edge function. On 429 we surface the server's
48	// retry_after_sec as "Try again in Xh Ym". On success we optimistically
49	// bump `last_refreshed_at` locally and subscribe to metric_snapshots
50	// inserts so webhook-driven denorm updates roll in without a reload.
51	
52	type SocialPlatform = Database['public']['Enums']['platform'];
53	type SocialLink = Database['public']['Tables']['social_links']['Row'];
54	type CreatorProfileRow = Database['public']['Tables']['creator_profiles']['Row'];
55	type MetricStatus = Database['public']['Enums']['metric_status'];
56	type SnapshotEntry = { status: MetricStatus; fetched_at: string };
57	
58	const HANDLE_RE = /^[a-zA-Z0-9_.]{1,30}$/;
59	const PLATFORMS: readonly SocialPlatform[] = ['tiktok', 'instagram'];
60	const REFRESH_THRESHOLD = 64;
61	const REFRESH_MAX_DRAG = 140;
62	
63	export default function CreatorProfile() {
64	  const { user, signOut } = useAuth();
65	  const { show: showToast } = useToast();
66	
67	  const [profile, setProfile] = useState<CreatorProfileRow | null>(null);
68	  const [links, setLinks] = useState<SocialLink[]>([]);
69	  const [snapshotByLink, setSnapshotByLink] = useState<Map<string, SnapshotEntry>>(new Map());
70	  const [loading, setLoading] = useState(true);
71	  const [pendingAction, setPendingAction] = useState<string | null>(null);
72	  const [sheetPlatform, setSheetPlatform] = useState<SocialPlatform | null>(null);
73	  const [refreshingLinkId, setRefreshingLinkId] = useState<string | null>(null);
74	  // Synchronous lock — React state updates are async, so the useCallback
75	  // closure's refreshingLinkId can be stale if two gestures fire back-to-back.
76	  // A ref gives us a write-on-call guard that every subsequent invocation
77	  // observes immediately (Codebase Pattern #82 — same stale-capture rule
78	  // that applies to Reanimated worklets applies to rapid JS-side event
79	  // handlers too).
80	  const refreshLock = useRef(false);
81	
82	  const load = useCallback(async () => {
83	    if (!user) return;
84	    setLoading(true);
85	    try {
86	      const [profileRes, linksRes] = await Promise.all([
87	        supabase
88	          .from('creator_profiles')
89	          .select('*')
90	          .eq('user_id', user.id)
91	          .maybeSingle(),
92	        supabase
93	          .from('social_links')
94	          .select('*')
95	          .eq('user_id', user.id)
96	          .neq('status', 'unlinked'),
97	      ]);
98	      if (profileRes.error) throw profileRes.error;
99	      if (linksRes.error) throw linksRes.error;
100	      const linkRows = linksRes.data ?? [];
101	      const linkIds = linkRows.map((l) => l.id);
102	      const snapshotMap = new Map<string, SnapshotEntry>();
103	      if (linkIds.length > 0) {
104	        const snapsRes = await supabase
105	          .from('metric_snapshots')
106	          .select('social_link_id, status, fetched_at')
107	          .eq('is_latest', true)
108	          .in('social_link_id', linkIds);
109	        if (snapsRes.error) throw snapsRes.error;
110	        for (const row of snapsRes.data ?? []) {
111	          snapshotMap.set(row.social_link_id, {
112	            status: row.status,
113	            fetched_at: row.fetched_at,
114	          });
115	        }
116	      }
117	      setProfile(profileRes.data ?? null);
118	      setLinks(linkRows);
119	      setSnapshotByLink(snapshotMap);
120	    } catch (err) {
121	      console.error('Profile load failed', err);
122	      showToast({ message: 'Could not load profile.', variant: 'error' });
123	    } finally {
124	      setLoading(false);
125	    }
126	  }, [user, showToast]);
127	
128	  useEffect(() => {
129	    void load();
130	  }, [load]);
131	
132	  // Realtime: when the apify-webhook (or cron) inserts a fresh/stale
133	  // metric_snapshots row for one of this creator's linked handles, the
134	  // denorm trigger also updates creator_profiles — reload everything so
135	  // the "Last refreshed" stamp + the denorm metric counts roll forward.
136	  // Keyed on a stable string of sorted link ids to avoid resubscribing on
137	  // every setLinks reference flip.
138	  const linkIdKey = useMemo(
139	    () => links.map((l) => l.id).sort().join(','),
140	    [links],
141	  );
142	
143	  useEffect(() => {
144	    if (!user || linkIdKey === '') return;
145	    const ids = linkIdKey.split(',');
146	    const token = getCachedToken();
147	    if (!token) return;
148	    let cancelled = false;
149	    let activeChannel: ReturnType<typeof supabase.channel> | null = null;
150	    // Realtime runs over a websocket — the marketifyFetch Authorization
151	    // wrapper in src/lib/supabase.ts only covers HTTP, so inject the JWT
152	    // into the Realtime client explicitly before subscribing. RLS then
153	    // applies metric_snapshots_self_read (us_035) to the stream.
154	    void supabase.realtime.setAuth(token).then(() => {
155	      if (cancelled) return;
156	      activeChannel = supabase
157	        .channel(`creator-metrics-${user.id}`)
158	        .on(
159	          'postgres_changes',
160	          {
161	            event: 'INSERT',
162	            schema: 'public',
163	            table: 'metric_snapshots',
164	            filter: `social_link_id=in.(${ids.join(',')})`,
165	          },
166	          (payload) => {
167	            const row = payload.new as { is_latest?: boolean; status?: MetricStatus };
168	            if (row.is_latest === true && (row.status === 'fresh' || row.status === 'stale')) {
169	              void load();
170	            }
171	          },
172	        )
173	        .subscribe();
174	    });
175	    return () => {
176	      cancelled = true;
177	      if (activeChannel) void supabase.removeChannel(activeChannel);
178	    };
179	  }, [user, linkIdKey, load]);
180	
181	  const onRefresh = useCallback(
182	    async (link: SocialLink) => {
183	      if (refreshLock.current) return;
184	      refreshLock.current = true;
185	      setRefreshingLinkId(link.id);
186	      try {
187	        const { data, error } = await supabase.functions.invoke<{
188	          status?: 'queued' | 'already_fresh';
189	        }>('metrics-refresh', { body: { social_link_id: link.id } });
190	        if (error) {
191	          const ctx = (error as { context?: unknown }).context;
192	          if (
193	            ctx &&
194	            typeof ctx === 'object' &&
195	            'status' in ctx &&
196	            typeof (ctx as { json?: unknown }).json === 'function'
197	          ) {
198	            const res = ctx as Response;
199	            let body: { error?: string; retry_after_sec?: number } = {};
200	            try {
201	              body = (await res.json()) as { error?: string; retry_after_sec?: number };
202	            } catch {
203	              // non-JSON body — fall through to generic toast
204	            }
205	            if (res.status === 429 && typeof body.retry_after_sec === 'number') {
206	              showToast({
207	                message: `Try again in ${formatRetryAfter(body.retry_after_sec)}`,
208	                variant: 'error',
209	              });
210	              return;
211	            }
212	            if (res.status === 422 && body.error === 'LINK_UNLINKED') {
213	              showToast({ message: 'Handle is no longer linked.', variant: 'error' });
214	              return;
215	            }
216	          }
217	          showToast({ message: 'Could not refresh metrics.', variant: 'error' });
218	          return;
219	        }
220	        if (data?.status === 'queued') {
221	          // Optimistic stamp so "Last refreshed" reads "just now" until the
222	          // Apify webhook lands and realtime triggers a reload. Scoped to
223	          // the queued path only — for `already_fresh` the server-side
224	          // fetched_at is already accurate (could be up to 6h old) and
225	          // bumping it would fake a fresh refresh on stale data.
226	          setSnapshotByLink((prev) => {
227	            const next = new Map(prev);
228	            const existing = next.get(link.id);
229	            next.set(link.id, {
230	              status: existing?.status ?? 'fresh',
231	              fetched_at: new Date().toISOString(),
232	            });
233	            return next;
234	          });
235	          showToast({ message: 'Refreshing metrics…', variant: 'success' });
236	        }
237	      } finally {
238	        refreshLock.current = false;
239	        setRefreshingLinkId(null);
240	      }
241	    },
242	    [showToast],
243	  );
244	
245	  const sections = useMemo(() => {
246	    return PLATFORMS.map((platform) => {
247	      const link = links.find((l) => l.platform === platform) ?? null;
248	      const snap = link ? snapshotByLink.get(link.id) ?? null : null;
249	      const isStale = snap?.status === 'stale';
250	      const lastRefreshedAt = snap?.fetched_at ?? null;
251	      return { platform, link, isStale, lastRefreshedAt };
252	    });
253	  }, [links, snapshotByLink]);
254	
255	  const onAdd = useCallback(
256	    async (platform: SocialPlatform, rawHandle: string) => {
257	      const handle = rawHandle.trim().replace(/^@+/, '').trim();
258	      if (!HANDLE_RE.test(handle)) {
259	        showToast({
260	          message: 'Handle must be letters, numbers, underscores, or dots.',
261	          variant: 'error',
262	        });
263	        return;
264	      }
265	      setPendingAction(`add:${platform}`);
266	      try {
267	        const { data, error } = await supabase.functions.invoke<{ social_link_id: string }>(
268	          'manage-social-link',
269	          { body: { action: 'add', platform, handle } },
270	        );
271	        if (error) {
272	          const ctx = (error as { context?: unknown }).context;
273	          if (
274	            ctx &&
275	            typeof ctx === 'object' &&
276	            'status' in ctx &&
277	            typeof (ctx as { json?: unknown }).json === 'function'
278	          ) {
279	            const res = ctx as Response;
280	            let body: { error?: string } = {};
281	            try {
282	              body = (await res.json()) as { error?: string };
283	            } catch {
284	              // non-JSON body — fall through to generic toast
285	            }
286	            if (res.status === 409 && body.error === 'ALREADY_LINKED') {
287	              showToast({
288	                message: `You already have a ${platformLabel(platform)} handle linked.`,
289	                variant: 'error',
290	              });
291	              return;
292	            }
293	            if (res.status === 409 && body.error === 'HANDLE_TAKEN') {
294	              showToast({
295	                message: 'That handle is already linked to another account.',
296	                variant: 'error',
297	              });
298	              return;
299	            }
300	          }
301	          showToast({ message: 'Could not add handle.', variant: 'error' });
302	          return;
303	        }
304	        if (!data?.social_link_id) {
305	          showToast({ message: 'Could not add handle.', variant: 'error' });
306	          return;
307	        }
308	        setSheetPlatform(null);
309	        showToast({
310	          message: `${platformLabel(platform)} handle added.`,
311	          variant: 'success',
312	        });
313	        await load();
314	      } finally {
315	        setPendingAction(null);
316	      }
317	    },
318	    [showToast, load],
319	  );
320	
321	  const onUnlink = useCallback(
322	    async (link: SocialLink) => {
323	      setPendingAction(`unlink:${link.id}`);
324	      try {
325	        const { error } = await supabase.functions.invoke('manage-social-link', {
326	          body: { action: 'unlink', social_link_id: link.id },
327	        });
328	        if (error) {
329	          showToast({ message: 'Could not unlink handle.', variant: 'error' });
330	          return;
331	        }
332	        showToast({
333	          message: `${platformLabel(link.platform)} handle unlinked.`,
334	          variant: 'success',
335	        });
336	        await load();
337	      } finally {
338	        setPendingAction(null);
339	      }
340	    },
341	    [showToast, load],
342	  );
343	
344	  return (
345	    <SafeAreaView style={styles.container}>
346	      <ScrollView contentContainerStyle={styles.scrollContent}>
347	        <View style={styles.header}>
348	          <Text style={[textStyles.display, { color: colors.ink }]}>Profile</Text>
349	          {user ? (
350	            <Text style={[textStyles.mono, styles.usernameRow]}>@{user.username}</Text>
351	          ) : null}
352	        </View>
353	
354	        {loading && profile === null ? (
355	          <View style={styles.loadingBlock}>
356	            <ActivityIndicator color={colors.ink} />
357	          </View>
358	        ) : (
359	          <View style={styles.sections}>
360	            {sections.map(({ platform, link, isStale, lastRefreshedAt }) => (
361	              <PlatformCard
362	                key={platform}
363	                platform={platform}
364	                link={link}
365	                profile={profile}
366	                isStale={isStale}
367	                lastRefreshedAt={lastRefreshedAt}
368	                pendingAction={pendingAction}
369	                refreshing={link !== null && refreshingLinkId === link.id}
370	                onOpenAdd={() => setSheetPlatform(platform)}
371	                onUnlink={onUnlink}
372	                onRefresh={onRefresh}
373	              />
374	            ))}
375	          </View>
376	        )}
377	
378	        <View style={styles.signOutWrap}>
379	          <ButtonSecondary
380	            label="Sign out"
381	            onPress={signOut}
382	            accessibilityLabel="Sign out"
383	            testID="creator-signout"
384	          />
385	        </View>
386	      </ScrollView>
387	
388	      <AddHandleSheet
389	        platform={sheetPlatform}
390	        onDismiss={() => setSheetPlatform(null)}
391	        onSubmit={onAdd}
392	        submitting={sheetPlatform !== null && pendingAction === `add:${sheetPlatform}`}
393	      />
394	    </SafeAreaView>
395	  );
396	}
